 921→            .map_err(|e| format!("failed to initialize spec cache: {e}"))?;
 922→        (Some(bm), Some(sc))
 923→    };
 924→
 925→    let parsed: Vec<Target> = targets
 926→        .iter()
 927→        .map(|t| parse_target(t))
 928→        .collect::<Result<Vec<_>, _>>()?;
 929→    validate_targets(&parsed)?;
 930→
 931→    let req_timeout = Duration::from_secs(request_timeout);
 932→
 933→    let mut file_spec_bundles: Vec<FileSpecBundle> = Vec::new();
 934→
 935→    let report_style = if use_color {
 936→        shatter_core::report_style::ReportStyle::ansi()
 937→    } else {
 938→        shatter_core::report_style::ReportStyle::default()
 939→    };
 940→
 941→    // Count total functions across all targets for header/footer.
 942→    let mut total_function_count: usize = 0;
 943→    let mut total_paths: usize = 0;
 944→    let mut total_covered: usize = 0;
 945→    let mut total_lines: u32 = 0;
 946→    let mut header_printed = false;
 947→
 948→    for target in &parsed {
 949→        let file_str = target.file.to_string_lossy();
 950→        let func_display = target
 951→            .function
 952→            .as_deref()
 953→            .unwrap_or("(all)");
 954→
 955→        let project_root_str = resolve_project_root(project_dir, &target.file);
 956→
 957→        if let Some(ref root) = project_root_str {
 958→            log::debug!("Project root: {root}");
 959→        }
 960→        log::debug!(
 961→            "Exploring {file_str}:{func_display} [language={}, max_iterations={max_iterations}]",
 962→            target.language.label()
 963→        );
 964→
 965→        let config = frontend_config(target.language, req_timeout, log_level, exec_timeout, build_timeout, memory_limit, None)?;
 966→        let mut frontend = Frontend::spawn(&config).await.map_err(|e| {
 967→            format!(
 968→                "failed to spawn {} frontend: {e}",
 969→                target.language.label()
 970→            )
 971→        })?;
 972→
 973→        log::debug!(
 974→            "Frontend connected (language={})",
 975→            frontend.language().unwrap_or("unknown")
 976→        );
 977→
 978→        // Analyze phase
 979→        let analyze_response = frontend
 980→            .send(ProtoCommand::Analyze {
 981→                file: file_str.to_string(),
 982→                function: target.function.clone(),
 983→                project_root: project_root_str.clone(),
 984→            })
 985→            .await
 986→            .map_err(|e| format!("analyze failed: {e}"))?;
 987→
 988→        match &analyze_response.result {
 989→            ResponseResult::Analyze { functions } => {
 990→                log::debug!("Found {} function(s):", functions.len());
 991→                for func in functions {
 992→                    log::debug!("  - {} ({} params, {} branches)",
 993→                        func.name,
 994→                        func.params.len(),
 995→                        func.branches.len(),
 996→                    );
 997→                }
 998→            }
 999→            ResponseResult::Error { code, message, .. } => {
1000→                log::error!("Analyze error ({code:?}): {message}");
1001→                shutdown_frontend(frontend).await;
1002→                continue;
1003→            }
1004→            other => {
1005→                log::error!("Unexpected analyze response: {other:?}");
1006→                shutdown_frontend(frontend).await;
1007→                continue;
1008→            }
1009→        }
1010→
1011→        let functions = match &analyze_response.result {
1012→            ResponseResult::Analyze { functions } => functions.clone(),
1013→            _ => unreachable!("already matched above"),
1014→        };
1015→
1016→        if analyze_only {
1017→            if log::log_enabled!(log::Level::Info) {
1018→                for func in &functions {
1019→                    eprintln!(
1020→                        "{}{}{}  ({file_str}:{})",
1021→                        colors.bold, func.name, colors.reset, func.start_line
1022→                    );
1023→                    eprintln!(
1024→                        "  {}params: {}, branches: {}{}",
1025→                        colors.dim,
1026→                        func.params.len(),
1027→                        func.branches.len(),
1028→                        colors.reset
1029→                    );
1030→                }
1031→            }
1032→            shutdown_frontend(frontend).await;
1033→            continue;
1034→        }
1035→
1036→        // Incremental plan: compare fingerprints against existing spec when --output is set
1037→        use std::collections::HashSet;
1038→        let incremental_plan = if let Some(out) = output_path
1039→            && !clean
1040→            && out.exists()
1041→        {
1042→            match shatter_core::spec::read_file_spec_bundle(out) {
1043→                Ok(existing) => {
1044→                    match shatter_core::spec::compute_incremental_plan(&target.file, &functions, &existing) {
1045→                        Ok(plan) => Some((plan, existing)),
1046→                        Err(e) => {
1047→                            log::debug!("Failed to compute incremental plan: {e}");
1048→                            None
1049→                        }
